import React from 'react';
import './Experience.css';

const EXPERIENCE = [
  {
    period: '2023 - Present',
    role: 'Senior Video Editor',
    company: 'Freelance',
    desc: 'Working with YouTube creators and brands across finance, sports, and lifestyle niches.',
  },
  {
    period: '2022 - 2023',
    role: 'Video Editor',
    company: 'Content Studio Pvt. Ltd.',
    desc: 'Produced 50+ videos per month for social media clients.',
  },
  {
    period: '2021 - 2022',
    role: 'Junior Editor',
    company: 'Digital Agency',
    desc: 'Started career editing short-form content and brand reels.',
  },
];

const SKILLS = {
  Editing: ['Premiere Pro', 'DaVinci Resolve', 'CapCut', 'Final Cut Pro'],
  Color: ['Color Grading', 'LUT Design', 'DaVinci Color', 'ACES Workflow'],
  Motion: ['After Effects', 'Motion Graphics', 'Lower Thirds', 'Titles'],
  Tools: ['Photoshop', 'Illustrator', 'Audition', 'Frame.io'],
};

export default function Experience() {
  return (
    <section id="experience" className="section experience-section reveal" data-delay="0">
      <div className="section-inner experience-grid">
        <div>
          <h2 className="section-heading">Experience</h2>
          <div className="timeline">
            {EXPERIENCE.map((item) => (
              <article className="timeline-item" key={`${item.period}-${item.role}`}>
                <p className="exp-period">{item.period}</p>
                <h3 className="exp-role">{item.role}</h3>
                <p className="exp-company">{item.company}</p>
                <p className="exp-desc">{item.desc}</p>
              </article>
            ))}
          </div>
        </div>

        <div>
          <h2 className="section-heading">Skills</h2>
          <div className="skill-groups">
            {Object.entries(SKILLS).map(([group, items]) => (
              <div className="skill-group" key={group}>
                <p className="skill-label">{group}</p>
                <div className="skill-pills">
                  {items.map((skill) => (
                    <span className="skill-pill" key={skill}>{skill}</span>
                  ))}
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </section>
  );
}
